// SheetThatOverlaysMultipleTimesStackingWith.tsx
import React, {useMemo} from 'react';
import {StyleSheet, View, Text, Pressable, Dimensions} from 'react-native';
import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {interpolate, useAnimatedStyle, useSharedValue, withSpring} from 'react-native-reanimated';
const SCREEN_H = Dimensions.get('window').height;
export function SheetThatOverlaysMultipleTimesStackingWith({open, onClose, children}: {open: boolean; onClose: () => void; children: React.ReactNode}) {
  const snaps = useMemo(() => [SCREEN_H * 0.74, SCREEN_H * 0.38, SCREEN_H * 0.1], []);
  const y = useSharedValue(open ? snaps[1] : SCREEN_H);
  const pan = Gesture.Pan().onUpdate((e) => { y.value = Math.max(snaps[2], snaps[1] + e.translationY); }).onEnd((e) => { const projected = y.value + e.velocityY * 0.16; const next = snaps.reduce((best, snap) => Math.abs(projected - snap) < Math.abs(projected - best) ? snap : best, snaps[0]); y.value = withSpring(next, {damping: 22, stiffness: 220}); });
  const sheetStyle = useAnimatedStyle(() => ({transform: [{translateY: y.value}]}));
  const backdropStyle = useAnimatedStyle(() => ({opacity: interpolate(y.value, [snaps[0], snaps[2]], [0.08, 0.46])}));
  return <View pointerEvents={open ? 'auto' : 'none'} style={StyleSheet.absoluteFill}><Animated.View style={[styles.backdrop, backdropStyle]} /><GestureDetector gesture={pan}><Animated.View style={[styles.sheet, sheetStyle]} accessibilityViewIsModal accessibilityLabel="Sheet that overlays multiple times (stacking with backdrop dim)"><View style={styles.handle} /><Text style={styles.title}>Sheet that overlays multiple times (stacking with backdrop dim)</Text>{children}<Pressable onPress={onClose} accessibilityRole="button" style={styles.close}><Text>Close</Text></Pressable></Animated.View></GestureDetector></View>;
}
const styles = StyleSheet.create({backdrop: {...StyleSheet.absoluteFillObject, backgroundColor: 'black'}, sheet: {position: 'absolute', left: 0, right: 0, height: SCREEN_H, borderTopLeftRadius: 24, borderTopRightRadius: 24, backgroundColor: 'white', padding: 18, gap: 12}, handle: {alignSelf: 'center', width: 42, height: 5, borderRadius: 3, backgroundColor: '#cbd5e1'}, title: {fontSize: 18, fontWeight: '700'}, close: {minHeight: 44, justifyContent: 'center'}});

