    setItems((current) => [...current, ...next]);
    for (const item of next) {
      setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'uploading'} : i));
      try { await upload(item, (progress) => setItems((current) => current.map(i => i.id === item.id ? {...i, progress} : i))); setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'done', progress: 1} : i)); }
      catch { setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'failed'} : i)); }
    }
  }, [upload]);
  return <View style={styles.wrap} accessibilityLabel="Document scanner with edge detection (iOS native)"><Pressable onPress={pick} accessibilityRole="button" accessibilityLabel="Choose media" style={styles.pick}><Text style={styles.pickText}>Add media</Text></Pressable><Text accessibilityLiveRegion="polite">{pendingCount} pending</Text><FlatList data={items} keyExtractor={(item) => item.id} numColumns={3} renderItem={({item}) => <View style={styles.tile}><Image source={{uri: item.uri}} style={styles.image} /><View style={[styles.progress, {width: `${Math.round(item.progress * 100)}%`}]} /><Text style={styles.badge}>{item.status}</Text></View>} /></View>;
}
const styles = StyleSheet.create({wrap: {gap: 12}, pick: {minHeight: 44, borderRadius: 12, alignItems: 'center', justifyContent: 'center', backgroundColor: '#111827'}, pickText: {color: 'white', fontWeight: '700'}, tile: {width: '33.33%', aspectRatio: 1, padding: 4}, image: {flex: 1, borderRadius: 12, backgroundColor: '#e5e7eb'}, progress: {position: 'absolute', left: 4, bottom: 4, height: 3, backgroundColor: '#22c55e'}, badge: {position: 'absolute', right: 8, bottom: 8, color: 'white', backgroundColor: 'rgba(0,0,0,0.55)', paddingHorizontal: 6, borderRadius: 8, overflow: 'hidden'}});

// MapDarkLightAutoSwitchOnTunnel.tsx
import React, {useCallback, useRef, useState} from 'react';
import {StyleSheet, View, Text, Pressable} from 'react-native';
import MapView, {Marker, Region} from 'react-native-maps';

type Place = {id: string; title: string; subtitle?: string; latitude: number; longitude: number};
const INITIAL_REGION: Region = {latitude: 37.7749, longitude: -122.4194, latitudeDelta: 0.08, longitudeDelta: 0.08};
export function MapDarkLightAutoSwitchOnTunnel({places, onPlaceOpen}: {places: Place[]; onPlaceOpen?: (place: Place) => void}) {
  const mapRef = useRef<MapView>(null);
  const [selected, setSelected] = useState<Place | null>(null);
  const focusPlace = useCallback((place: Place) => {
    setSelected(place);
    mapRef.current?.animateCamera({center: {latitude: place.latitude, longitude: place.longitude}, zoom: 15}, {duration: 280});
  }, []);
  return (
    <View style={styles.wrap} accessibilityLabel="Map dark/light auto-switch on tunnel/inside">
      <MapView ref={mapRef} style={StyleSheet.absoluteFill} initialRegion={INITIAL_REGION} showsUserLocation>
        {places.map((place) => <Marker key={place.id} coordinate={{latitude: place.latitude, longitude: place.longitude}} title={place.title} description={place.subtitle} onPress={() => focusPlace(place)} />)}
      </MapView>
      {selected && <View style={styles.sheet} accessibilityRole="summary"><Text style={styles.title}>{selected.title}</Text><Text style={styles.subtitle}>{selected.subtitle ?? 'Nearby place'}</Text><Pressable onPress={() => onPlaceOpen?.(selected)} accessibilityRole="button" style={styles.action}><Text style={styles.actionText}>Open</Text></Pressable></View>}
    </View>
  );
}
const styles = StyleSheet.create({wrap: {height: 320, borderRadius: 18, overflow: 'hidden', backgroundColor: '#dbeafe'}, sheet: {position: 'absolute', left: 12, right: 12, bottom: 12, padding: 14, borderRadius: 16, backgroundColor: 'white', elevation: 8}, title: {fontWeight: '700', fontSize: 16}, subtitle: {marginTop: 4, color: '#4b5563'}, action: {marginTop: 10, minHeight: 44, alignItems: 'center', justifyContent: 'center', borderRadius: 12, backgroundColor: '#111827'}, actionText: {color: 'white', fontWeight: '700'}});

